from flask import Flask, request
from itsdangerous import URLSafeTimedSerializer
import smtplib
from email.mime.multipart import MIMEMultipart
from email.mime.text import MIMEText

app = Flask(__name__)
s = URLSafeTimedSerializer('Thisisasecret!')

# simulate Database
database = {}

@app.route('/reset_password', methods=['POST'])
def reset_password():
    email = request.json.get('email')
    token = s.dumps(email, salt='email-confirm')
    
    # Store token in database
    database[email] = token
    
    # Send reset link via email
    msg = MIMEMultipart()
    msg['From'] = 'reset@myapp.com'
    msg['To'] = email
    msg['Subject'] = 'Password reset requested'
    msg.attach(MIMEText('Please click on the link below to reset your password.', 'plain'))
    link = "http://localhost:5000/reset_password/{}".format(token)
    msg.attach(MIMEText(link, 'plain'))
    
    server = smtplib.SMTP('my.smtp.server', 587)  
    server.starttls()  
    server.login(msg['From'], 'mypassword') 
    server.sendmail(msg['From'], msg['To'], msg.as_string())
    server.quit()
    
    return {"status": "Password reset link has been sent to your email address."}

if __name__ == "__main__":
    app.run(debug=True, port=5000)